	@echo "Applying infrastructure changes for $(ENV)..."
	@echo "WARNING: This will modify infrastructure in $(ENV)"
	@read -p "Continue? [y/N] " -n 1 -r; \
	echo; \
	if [[ $$REPLY =~ ^[Yy]$$ ]]; then \
		cd $(_get_path) && terraform apply tfplan; \
	else \
		echo "Cancelled"; \
	fi

