.PHONY: help init validate plan apply destroy fmt lint clean output init-global init-all apply-global apply-all

# Environment selection (global, dev, staging, prod)
ENV ?= dev

help:
	@echo "Terraform Infrastructure Management"
	@echo "===================================="
	@echo "Usage: make [target] ENV=<global|dev|prod>"
	@echo ""
	@echo "Targets:"
	@echo "  init         - Initialize Terraform for ENV (default: dev)"
	@echo "  init-global  - Initialize global shared resources"
	@echo "  init-all     - Initialize global + all environments"
	@echo "  validate     - Validate Terraform configuration"
	@echo "  plan         - Create execution plan"
	@echo "  apply        - Apply infrastructure changes"
	@echo "  apply-global - Apply global resources"
	@echo "  apply-all    - Apply global resources + all environments (use with caution)"
	@echo "  destroy      - Destroy all infrastructure"
	@echo "  fmt          - Format Terraform files"
	@echo "  lint         - Run linting checks"
	@echo "  clean        - Remove Terraform state and lock files"
	@echo "  output       - Display outputs for ENV"
	@echo ""
	@echo "Examples:"
	@echo "  make init ENV=global        # Initialize shared resources"
	@echo "  make init ENV=dev           # Initialize dev environment"
	@echo "  make init-all               # Initialize all (global + dev/prod)"
	@echo "  make plan ENV=dev           # Plan dev infrastructure"
	@echo "  make apply ENV=global       # Deploy global resources"
	@echo "  make apply-all              # Deploy everything (global + all environments)"

