##
## Description: Global Variables - Shared across all environments
## Purpose: Define shared configuration for global resources (container registry, etc)
## Author: Raul Peña (rpena@shokworks.io)
##
## These variables are used by all environments but the values remain consistent
## since global resources are shared. For environment-specific variables,
## see environments/*/variables.tf

# ============================================================================
# NAMING CONVENTION VARIABLES
# ============================================================================
# Used to construct consistent resource names across all global resources

variable "company_name" {

  description = "Company name for resource naming convention"
  type        = string
  default     = "intellxxdna"

  validation {
    condition     = can(regex("^[a-z0-9-]+$", var.company_name))
    error_message = "Company name must contain only lowercase letters, numbers, and hyphens."
  }
}

variable "project_name" {

  description = "Project name for resource naming convention"
  type        = string
  default     = "lexxi"

  validation {
    condition     = can(regex("^[a-z0-9-]+$", var.project_name))
    error_message = "Project name must contain only lowercase letters, numbers, and hyphens."
  }
}

variable "registry_name" {

  description = "Azure Container Registry name (globally unique, lowercase, alphanumeric)"
  type        = string
  default     = "ixdnaacrshared"

  validation {
    condition     = can(regex("^[a-z0-9]+$", var.registry_name))
    error_message = "Registry name must contain only lowercase letters and numbers."
  }
}



# ============================================================================
# DEPLOYMENT VARIABLES
# ============================================================================
# Control where and how resources are deployed

variable "azure_region" {

  description = "Azure region for resource deployment (e.g., eastus2, westus2, northeurope)"
  type        = string
  default     = "eastus2"

  validation {
    condition     = can(regex("^[a-z0-9]+$", var.azure_region))
    error_message = "Azure region must be a valid region name."
  }
}

variable "environment" {

  description = "Environment designation (development, staging, production)"
  type        = string
  default     = "development"

  # NOTE: Global resources are shared, but this variable is kept for consistency
  # and future use if environment-specific global resources are needed
  validation {
    condition     = contains(["development", "staging", "production", "shared"], var.environment)
    error_message = "Environment must be development, staging, production, or shared."
  }
}



# ============================================================================
# TAGGING & ORGANIZATION VARIABLES
# ============================================================================
# For resource organization, cost allocation, and compliance

variable "common_tags" {

  description = "Common tags applied to all global resources for organization and tracking"
  type        = map(string)
  default = {
    ManagedBy   = "Terraform"
    CreatedDate = "2026"
  }

  # These tags are merged with environment-specific tags in locals.tf
}

