## Basic environment identifiers and cloud region settings
##

variable "environment" {

  description = "Environment name (dev/staging/prod)"
  type        = string
  default     = "prod"
}

variable "azure_region" {

  description = "Azure region for deployment (e.g., eastus2, westus2, eastus22)"
  type        = string
  default     = "eastus2"
}



##=============================================================================
