## Makefile for common Terraform operations
## Usage: make help

.PHONY: help init validate plan apply destroy fmt lint clean output init-global init-all apply-global apply-all

# Environment selection (global, dev, staging, prod)
ENV ?= dev

help:
	@echo "Terraform Infrastructure Management"
	@echo "===================================="
	@echo "Usage: make [target] ENV=<global|dev|prod>"
	@echo ""
	@echo "Targets:"
	@echo "  init         - Initialize Terraform for ENV (default: dev)"
	@echo "  init-global  - Initialize global shared resources"
	@echo "  init-all     - Initialize global + all environments"
	@echo "  validate     - Validate Terraform configuration"
	@echo "  plan         - Create execution plan"
	@echo "  apply        - Apply infrastructure changes"
	@echo "  apply-global - Apply global resources"
	@echo "  apply-all    - Apply global resources + all environments (use with caution)"
	@echo "  destroy      - Destroy all infrastructure"
	@echo "  fmt          - Format Terraform files"
	@echo "  lint         - Run linting checks"
	@echo "  clean        - Remove Terraform state and lock files"
	@echo "  output       - Display outputs for ENV"
	@echo ""
	@echo "Examples:"
	@echo "  make init ENV=global        # Initialize shared resources"
	@echo "  make init ENV=dev           # Initialize dev environment"
	@echo "  make init-all               # Initialize all (global + dev/prod)"
	@echo "  make plan ENV=dev           # Plan dev infrastructure"
	@echo "  make apply ENV=global       # Deploy global resources"
	@echo "  make apply-all              # Deploy everything (global + all environments)"

# Helper function to detect path based on ENV
_get_path = $(if $(filter global,$(ENV)),global,environments/$(ENV))

init:
	@echo "Initializing Terraform for $(ENV)..."
	cd $(_get_path) && terraform init

init-global:
	@echo "Initializing Terraform for global shared resources..."
	cd global && terraform init

init-all:
	@echo "Initializing global shared resources..."
	cd global && terraform init
	@echo "Initializing dev environment..."
	cd environments/dev && terraform init
	@echo "Initializing prod environment..."
	cd environments/prod && terraform init
	@echo "✅ All initializations complete"

validate:
	@echo "Validating Terraform configuration for $(ENV)..."
	cd $(_get_path) && terraform validate

fmt:
	@echo "Formatting all Terraform files..."
	terraform fmt -recursive

lint:
	@echo "Linting Terraform files..."
	terraform validate
	@echo "Checking for common issues..."
	@find . -name "*.tf" -type f | xargs grep -l "TODO\|FIXME" || echo "No TODOs found"

plan:
	@echo "Planning infrastructure changes for $(ENV)..."
	cd $(_get_path) && terraform plan -out=tfplan

apply:
	@echo "Applying infrastructure changes for $(ENV)..."
	@echo "WARNING: This will modify infrastructure in $(ENV)"
	@read -p "Continue? [y/N] " -n 1 -r; \
	echo; \
	if [[ $$REPLY =~ ^[Yy]$$ ]]; then \
		cd $(_get_path) && terraform apply tfplan; \
	else \
		echo "Cancelled"; \
	fi

apply-global:
	@echo "Applying infrastructure changes for GLOBAL resources..."
	@echo "WARNING: This will create shared resources used by all environments"
	@read -p "Continue? [y/N] " -n 1 -r; \
	echo; \
	if [[ $$REPLY =~ ^[Yy]$$ ]]; then \
		cd global && terraform apply tfplan; \
	else \
		echo "Cancelled"; \
	fi

apply-all:
	@echo "=========================================="
	@echo "WARNING: This will deploy EVERYTHING"
	@echo "- Global shared resources"
	@echo "- Dev environment"
	@echo "- Prod environment"
	@echo "=========================================="
	@read -p "Are you SURE? [y/N] " -n 1 -r; \
	echo; \
	if [[ $$REPLY =~ ^[Yy]$$ ]]; then \
		echo "Deploying global resources..."; \
		cd global && terraform apply tfplan; \
		echo ""; \
		echo "Deploying dev environment..."; \
		cd ../environments/dev && terraform apply tfplan; \
		echo ""; \
		echo "Deploying prod environment..."; \
		cd ../prod && terraform apply tfplan; \
		echo ""; \
		echo "✅ All deployments complete"; \
	else \
		echo "Cancelled"; \
	fi

destroy:
	@echo "WARNING: This will DESTROY all infrastructure in $(ENV)"
	@read -p "Are you sure? Type 'yes' to confirm: " confirm; \
	if [ "$$confirm" = "yes" ]; then \
		cd $(_get_path) && terraform destroy; \
	else \
		echo "Cancelled"; \
	fi

output:
	@echo "Outputs for $(ENV):"
	cd $(_get_path) && terraform output

clean:
	@echo "Cleaning up Terraform files..."
	find . -type d -name ".terraform" -exec rm -rf {} + 2>/dev/null || true
	find . -name "terraform.tfstate*" -delete
	find . -name ".terraform.lock.hcl" -delete
	find . -name "*.tfplan" -delete
	@echo "Clean complete"

.DEFAULT_GOAL := help

